'use client';
import React from 'react';
import { useParams } from 'next/navigation';
import { useJournal } from '../../../hooks/useJournal';
import type { Block } from '../../../lib/types';
import BlockEditor from '../../../components/journal/editor/BlockEditor';

export default function JournalPage() {
  const params = useParams();
  const id = params.id as string;
  const { getEntry, updateEntry } = useJournal();
  const entry = getEntry(id);

  if (!entry) {
    return <div>Loading...</div>;
  }

  const handleTitleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateEntry(id, { title: e.target.value });
  };

  const handleBlocksChange = (blocks: Block[]) => {
    updateEntry(id, { blocks });
  };

  return (
    <div className="max-w-3xl mx-auto p-6">
      <input
        type="text"
        value={entry.title}
        onChange={handleTitleChange}
        placeholder="Untitled"
        className="w-full text-3xl font-bold mb-6 bg-transparent outline-none text-black dark:text-white"
      />
      <BlockEditor
        initialBlocks={entry.blocks}
        onBlocksChange={handleBlocksChange}
      />
    </div>
  );
} 