"use client"

import React, { useState, useEffect, useRef } from "react"
import { BlockType } from "@/lib/types"
import type { Block } from "@/lib/types"
import SlashCommandMenu from './SlashMenu'
import EditorContent from './EditorContent'
import EmptyState from './JournalWelcomeCard'

interface BlockEditorProps {
  initialBlocks?: Block[];
  onBlocksChange?: (blocks: Block[]) => void;
}

export default function BlockEditor({ initialBlocks, onBlocksChange }: BlockEditorProps) {
  const [blocks, setBlocksState] = useState<Block[]>(() =>
    initialBlocks ?? [
      { id: Date.now().toString(), type: BlockType.Text, content: "", isFocused: true },
    ]
  )

  useEffect(() => {
    if (initialBlocks) {
      setBlocksState(initialBlocks)
    }
  }, [initialBlocks])

  const setBlocks = (updatedBlocks: Block[]) => {
    setBlocksState(updatedBlocks)
    onBlocksChange?.(updatedBlocks)
  }

  const [showSlashMenu, setShowSlashMenu] = useState(false)
  const [slashMenuPosition, setSlashMenuPosition] = useState({ top: 0, left: 0 })
  const [currentBlockId, setCurrentBlockId] = useState<string>(blocks[0]?.id || "")

  const editorRef = useRef<HTMLDivElement>(null)

  const handleKeyDown = (e: React.KeyboardEvent, blockId: string) => {
    const blockIndex = blocks.findIndex((b) => b.id === blockId)
    if (blockIndex === -1) return
    const block = blocks[blockIndex]

    if (e.key === "/" && block.content === "") {
      e.preventDefault()
      setShowSlashMenu(true)
      const blockElement = document.getElementById(`block-${blockId}`)
      if (blockElement) {
        const rect = blockElement.getBoundingClientRect()
        setSlashMenuPosition({
          top: rect.bottom,
          left: rect.left,
        })
      }
    } else if (e.key === "Escape" && showSlashMenu) {
      setShowSlashMenu(false)
    } else if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault()
      const newBlock: Block = {
        id: Date.now().toString(),
        type: BlockType.Text,
        content: "",
        isFocused: true,
      }
      const updatedBlocks = [...blocks]
      updatedBlocks[blockIndex] = { ...updatedBlocks[blockIndex], isFocused: false }
      updatedBlocks.splice(blockIndex + 1, 0, newBlock)
      setBlocks(updatedBlocks)
      setCurrentBlockId(newBlock.id)
    } else if (e.key === "Backspace" && block.content === "" && blocks.length > 1) {
      e.preventDefault()
      const updatedBlocks = [...blocks]
      updatedBlocks.splice(blockIndex, 1)
      const newFocusIndex = Math.max(0, blockIndex - 1)
      updatedBlocks[newFocusIndex] = { ...updatedBlocks[newFocusIndex], isFocused: true }
      setBlocks(updatedBlocks)
      setCurrentBlockId(updatedBlocks[newFocusIndex].id)
    }
  }

  const handleBlockChange = (id: string, content: string) => {
    setBlocks(blocks.map((block) => (block.id === id ? { ...block, content } : block)))
  }

  const handleBlockFocus = (id: string) => {
    setBlocks(blocks.map((block) => ({ ...block, isFocused: block.id === id })))
    setCurrentBlockId(id)
  }

  const handleCommandSelect = (blockType: BlockType) => {
    setShowSlashMenu(false)
    setBlocks(
      blocks.map((block) =>
        block.id === currentBlockId ? { ...block, type: blockType, content: "" } : block
      )
    )
  }

  return (
    <div ref={editorRef} className="max-w-3xl mx-auto">
      {blocks.length === 0 ? (
        <EmptyState
          onCreateBlock={() =>
            setBlocks([
              { id: Date.now().toString(), type: BlockType.Text, content: "", isFocused: true },
            ])
          }
        />
      ) : (
        <EditorContent
          blocks={blocks}
          onKeyDown={handleKeyDown}
          onChange={handleBlockChange}
          onFocus={handleBlockFocus}
        />
      )}
      {showSlashMenu && (
        <SlashCommandMenu
          position={slashMenuPosition}
          onSelect={handleCommandSelect}
          onClose={() => setShowSlashMenu(false)}
        />
      )}
    </div>
  )
}
